  ('pukao-1fb53453-moex-00377', 'pukao-1fb53453', 'pukao-1fb53453-moex-110-d1a761c9', 'sub-pukao-1fb53453-02', NULL, 'single_choice', '關於行政機關管轄權之敘述，下列何者錯誤？', '["行政機關之管轄權，原則上應依據組織法規或其他行政法規定之", "基於管轄權恆定原則，無論何種情形下管轄權皆不可能發生變動", "數機關就同一事件依法皆有管轄權者，依受理先後順序判定", "關於管轄權之有無，行政機關應依職權調查"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:54+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "418", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財經廉政"}'::jsonb, NULL),
