  ('pukao-1fb53453-moex-00379', 'pukao-1fb53453', 'pukao-1fb53453-moex-110-d1a761c9', 'sub-pukao-1fb53453-02', NULL, 'single_choice', '依公務員懲戒法之規定，關於懲戒處分，下列敘述何者正確？', '["申誡處分，得以口頭或書面為之", "受降級處分者，依現職之俸（薪）級降一級至三級改敘", "罰款之懲戒處分得與剝奪、減少退休（職、伍）金之懲戒處分併為處分", "剝奪、減少退休（職、伍）金之懲戒處分，以退休（職、伍）或其他原因離職之公務員為限"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:54+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "418", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財經廉政"}'::jsonb, NULL),
  ('pukao-1fb53453-moex-00380', 'pukao-1fb53453', 'pukao-1fb53453-moex-110-d1a761c9', 'sub-pukao-1fb53453-02', NULL, 'single_choice', '依公務人員考績法之規定，關於公務人員考績之敘述，下列何者錯誤？', '["年終考績應以平時考核為依據，就受考人之工作、操行、學識、才能行之", "平時考核之獎勵分嘉獎、記功、記大功；懲處分申誡、記過、記大過", "平時考核之獎懲得互相抵銷，無獎懲抵銷而累積達二大過者，年終考績應列丙等", "任本職等年終考績已2年列甲等者，取得同官等高一職等之任用資格"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:54+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "418", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財經廉政"}'::jsonb, NULL),
  ('pukao-1fb53453-moex-00381', 'pukao-1fb53453', 'pukao-1fb53453-moex-110-d1a761c9', 'sub-pukao-1fb53453-02', NULL, 'single_choice', '依公務員服務法之規定，下列敘述何者錯誤？', '["公務員服務法對於其他公營事業機關之服務人員，亦有適用", "公務員於其離職後3年內，不得擔任與其離職前5年內之職務直接相關之營利事業董事", "機關首長兼任教學或研究工作者，應經上級主管機關許可", "公務員不得投資非屬其服務機關監督之農、工、礦、交通或新聞出版事業"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:54+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "418", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財經廉政"}'::jsonb, NULL),
  ('pukao-1fb53453-moex-00382', 'pukao-1fb53453', 'pukao-1fb53453-moex-110-d1a761c9', 'sub-pukao-1fb53453-02', NULL, 'single_choice', '依最高行政法院實務見解，關於公務人員權利救濟之敘述，下列何者正確？', '["公務人員如單就年終考績評定不服而循序提起行政訴訟時，原則上應以銓敘部為被告", "公務人員對於經考列丙等之年終考績，如有不服，得於申訴、再申訴後，提起行政訴訟以資救濟", "任主管人員之公務人員不服將其調任為非主管人員時，因已喪失主管加給，得循序提起行政訴訟以資 救濟", "公務人員如就考績獎懲結果之銓敘審定不服而循序提起行政訴訟時，原則上應以銓敘部為被告"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:54+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "418", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財經廉政"}'::jsonb, NULL),
